interface User {
  id: number;
  name: string;
  email: string;
  address: { city: string; zip: string };
}

// Look up one property's type
type UserId   = User['id'];      // number
type UserName = User['name'];    // string

// Look up a nested property (chain two accesses)
type City = User['address']['city']; // string

// Look up multiple keys at once (union of keys → union of value types)
type NameOrEmail = User['name' | 'email']; // string | string = string

// Look up all value types using keyof
type UserValues = User[keyof User];
// number | string | { city: string; zip: string }

// Array element type
type StringArray = string[];
type Elem = StringArray[number]; // string

// Works on readonly arrays too
const CONFIG = ['dev', 'staging', 'prod'] as const;
type EnvName = typeof CONFIG[number]; // 'dev' | 'staging' | 'prod'

// Tuple element types
type Pair = [string, number];
type First  = Pair[0];        // string
type Second = Pair[1];        // number
type Either = Pair[0 | 1];    // string | number

// Extracting a named tuple member (TS 4.0+)
type Named = [id: number, name: string, active: boolean];
type IdType = Named[0];  // number

// Derive a type from the keys of a const object
const STATUS = {
  pending:  'pending',
  approved: 'approved',
  rejected: 'rejected',
} as const;

type StatusKey   = keyof typeof STATUS;           // 'pending' | 'approved' | 'rejected'
type StatusValue = typeof STATUS[StatusKey];      // 'pending' | 'approved' | 'rejected'

// Look up a subset of keys
type ApprovalStatus = typeof STATUS['approved' | 'rejected']; // 'approved' | 'rejected'

// Common pattern: prevent duplication between a runtime object and its types
function isStatus(s: string): s is StatusValue {
  return Object.values(STATUS).includes(s as StatusValue);
}

interface ApiResponse {
  status: number;
  data: {
    users: Array<{
      id: string;
      profile: {
        displayName: string;
        avatar: string | null;
      };
      permissions: ('read' | 'write' | 'admin')[];
    }>;
    pagination: { page: number; total: number };
  };
}

// Extract deeply nested types without duplicating interfaces
type UserItem      = ApiResponse['data']['users'][number];
// { id: string; profile: { displayName: string; avatar: string | null }; permissions: ... }

type UserProfile   = ApiResponse['data']['users'][number]['profile'];
// { displayName: string; avatar: string | null }

type Permission    = ApiResponse['data']['users'][number]['permissions'][number];
// 'read' | 'write' | 'admin'

type PaginationInfo = ApiResponse['data']['pagination'];
// { page: number; total: number }

// Type-safe property getter
function getProperty<T, K extends keyof T>(obj: T, key: K): T[K] {
  return obj[key];
}

interface Product { id: string; name: string; price: number; }
const product: Product = { id: 'p1', name: 'Widget', price: 9.99 };

const name  = getProperty(product, 'name');  // string — T[K] = Product['name']
const price = getProperty(product, 'price'); // number — T[K] = Product['price']
// getProperty(product, 'unknown'); // Error: 'unknown' is not keyof Product

// Type-safe property setter with value type constraint
function setProperty<T, K extends keyof T>(obj: T, key: K, value: T[K]): void {
  obj[key] = value;
}

setProperty(product, 'price', 12.99); // ok — number
setProperty(product, 'price', '12');  // Error: string is not assignable to number

// Multiple correlated keys
function swap<T, K1 extends keyof T, K2 extends keyof T>(
  obj: T, k1: K1, k2: K2
): void {
  const tmp = obj[k1] as T[K1 | K2];
  obj[k1] = obj[k2] as T[K1];
  obj[k2] = tmp as T[K2];
}

import { FormControl, FormGroup } from '@angular/forms';

// Derive form control types from a data model
interface LoginForm {
  username: string;
  password: string;
  rememberMe: boolean;
}

// Pick the type of a specific form field
type UsernameControl = FormControl<LoginForm['username']>; // FormControl<string>
type RememberControl = FormControl<LoginForm['rememberMe']>; // FormControl<boolean>

// Build a typed form group where each control is typed to its field
type TypedFormGroup<T extends object> = FormGroup<{
  [K in keyof T]: FormControl<T[K]>
}>;

const form: TypedFormGroup<LoginForm> = new FormGroup({
  username:   new FormControl('', { nonNullable: true }),
  password:   new FormControl('', { nonNullable: true }),
  rememberMe: new FormControl(false, { nonNullable: true }),
});

const uName = form.controls.username.value; // string — correctly typed

import { createFeatureSelector, createSelector } from '@ngrx/store';

interface AppState {
  user: {
    profile: { name: string; avatar: string };
    preferences: { theme: 'light' | 'dark'; language: string };
  };
  products: {
    items: { id: string; price: number }[];
    loading: boolean;
  };
}

// Use indexed access to keep selector return types in sync with state shape
const selectUser = createFeatureSelector<AppState['user']>('user');
// return type: AppState['user']  — automatically updated when AppState.user changes

const selectPreferences = createSelector(
  selectUser,
  (user): AppState['user']['preferences'] => user.preferences
);
// return type: { theme: 'light' | 'dark'; language: string }

const selectTheme = createSelector(
  selectPreferences,
  (prefs): AppState['user']['preferences']['theme'] => prefs.theme
);
// return type: 'light' | 'dark'  — not string

import { HttpClient } from '@angular/common/http';
import { Observable } from 'rxjs';

interface ApiEndpoints {
  '/users':          { list: User[];    detail: User };
  '/products':       { list: Product[]; detail: Product };
  '/orders':         { list: Order[];   detail: Order };
}

// Extract list / detail types per endpoint
type ListResponse<E extends keyof ApiEndpoints> = ApiEndpoints[E]['list'];
type DetailResponse<E extends keyof ApiEndpoints> = ApiEndpoints[E]['detail'];

// Typed API service — return type is derived from the endpoint key
class ApiService {
  constructor(private http: HttpClient) {}

  list<E extends keyof ApiEndpoints>(endpoint: E): Observable<ListResponse<E>> {
    return this.http.get<ListResponse<E>>(endpoint);
  }

  detail<E extends keyof ApiEndpoints>(endpoint: E, id: string): Observable<DetailResponse<E>> {
    return this.http.get<DetailResponse<E>>(`${endpoint}/${id}`);
  }
}

const api = inject(ApiService);
api.list('/users');       // Observable<User[]>
api.detail('/products', '1'); // Observable<Product>

// Extract only the function properties from a type
type FunctionProperties<T> = {
  [K in keyof T]: T[K] extends Function ? K : never
}[keyof T];

interface Service {
  name: string;
  getUser(id: string): Promise<User>;
  getCount(): number;
  destroy(): void;
}

type ServiceMethods = FunctionProperties<Service>;
// 'getUser' | 'getCount' | 'destroy'

// Get the return type of a specific method
type GetUserReturn = ReturnType<Service['getUser']>; // Promise<User>

// Extract optional property keys
type OptionalKeys<T> = {
  [K in keyof T]-?: {} extends Pick<T, K> ? K : never
}[keyof T];

interface Draft {
  title: string;
  body: string;
  tags?: string[];
  publishedAt?: Date;
}

type DraftOptionals = OptionalKeys<Draft>; // 'tags' | 'publishedAt'
